1	// Shared artifact grouping helpers.
2	// Keep prefix derivation in one place so list and detail views agree.
3	
4	// prefixOf("docs/helix/01-frame/prd.md") => "docs"
5	// prefixOf("/library/personas/x.md") => "library"
6	const PREFIX_RE = /^\/?([^/]+)/;
7	
8	export function prefixOf(path: string): string {
9		const m = path.match(PREFIX_RE);
10		return m ? m[1] : '';
11	}
