1	// Group derivations for the artifacts list page.
2	// Pure, regex-based; safe to run on every render.
3	
4	export type GroupBy = import('$lib/urlState').GroupBy;
5	import { prefixOf } from '$lib/artifacts/grouping';
6	
7	// folderOf("docs/helix/01-frame/prd.md") => "docs/helix/01-frame"
8	// folderOf("README.md") => "/"
9	const FOLDER_RE = /^(.*)\/[^/]+$/;
10	export function folderOf(path: string): string {
11		const m = path.match(FOLDER_RE);
12		if (!m) return '/';
13		return m[1] || '/';
14	}
15	
16	export { prefixOf };
17	
18	// Workflow stage derivation. Matches the canonical HELIX-style numbered
19	// stage segment (e.g. 01-frame, 02-design) anywhere in the path. Returns
20	// the bare stage name lowercased, or null when no stage segment is found.
21	const STAGE_RE = /(?:^|\/)\d{2}-([a-z][a-z0-9-]*)(?:\/|$)/i;
22	export function workflowStageOf(path: string): string | null {
23		const m = path.match(STAGE_RE);
24		return m ? m[1].toLowerCase() : null;
25	}
26	
27	// Whether the workflow-stage axis should be shown for the given paths.
28	// The axis is hidden when no artifact in view has a derivable stage.
29	export function axisAvailable(paths: Iterable<string>): boolean {
30		for (const p of paths) {
31			if (workflowStageOf(p) !== null) return true;
32		}
33		return false;
34	}
35	
36	export interface Groupable {
37		path: string;
38		mediaType: string;
39	}
40	
41	// Generic, project-neutral label for the workflow-stage axis.
42	export const WORKFLOW_STAGE_LABEL = 'Workflow stage';
43	
44	export const WORKFLOW_STAGE_FALLBACK_LABEL = 'Unstaged';
45	
46	export function groupKey(item: Groupable, by: GroupBy): string {
47		switch (by) {
48			case 'folder':
49				return folderOf(item.path);
50			case 'prefix':
51				return prefixOf(item.path);
52			case 'mediaType':
53				return item.mediaType || 'unknown';
54			case 'workflowStage':
55				return workflowStageOf(item.path) ?? WORKFLOW_STAGE_FALLBACK_LABEL;
56		}
57	}
58	
59	export function groupItems<T extends Groupable>(
60		items: T[],
61		by: GroupBy
62	): { key: string; items: T[] }[] {
63		const buckets = new Map<string, T[]>();
64		for (const it of items) {
65			const k = groupKey(it, by);
66			const arr = buckets.get(k);
67			if (arr) arr.push(it);
68			else buckets.set(k, [it]);
69		}
70		return Array.from(buckets.entries())
71			.sort(([a], [b]) => a.localeCompare(b))
72			.map(([key, items]) => ({ key, items }));
73	}
74	
75	export const GROUP_BY_LABELS: Record<GroupBy, string> = {
76		folder: 'Folder',
77		prefix: 'Prefix',
78		mediaType: 'Media type',
79		workflowStage: WORKFLOW_STAGE_LABEL
80	};
81	
82	export const GROUP_BY_OPTIONS: { value: GroupBy; label: string }[] = [
83		{ value: 'folder', label: GROUP_BY_LABELS.folder },
84		{ value: 'prefix', label: GROUP_BY_LABELS.prefix },
85		{ value: 'mediaType', label: GROUP_BY_LABELS.mediaType },
86		{ value: 'workflowStage', label: WORKFLOW_STAGE_LABEL }
87	];
88	
89	export function groupCountLabel(
90		groupCount: number,
91		loadedCount: number,
92		hasNextPage: boolean
93	): string {
94		return hasNextPage ? `${groupCount} of ${loadedCount} loaded` : `${groupCount}`;
95	}
