13	export function readPersistedGroupBy(storage: GroupByStorage, projectId: string): GroupBy | null {
14		const raw = storage.getItem(groupByStorageKey(projectId));
15		if (raw === 'folder' || raw === 'prefix' || raw === 'mediaType' || raw === 'workflowStage') {
16			return raw;
17		}
18		return null;
19	}
